#include<bits/stdc++.h>
using namespace std;
int a,b;
int exgcd(int a,int b,int &x,int &y){
	if(b==0)return x=1,y=0,a;
	int r=exgcd(b,a%b,x,y);
	int fx = x, fy = y;
	x = fy;
	y = fx - (a / b) * fy; 
	return r;
}
int g(int a,int b){
	if(b==0)return a;
	return g(b,a%b);
}
int main()
{
	int t;
	cin>>t;
	while(t--){
		int a,b,c,x1,y1;
		cin>>a>>b>>c;
		int gcd=exgcd(a,b,x1,y1);
		if(c%gcd){
			cout<<-1<<"\n";
			continue;
		}
		int x0=c/gcd*x1,y0=c/gcd*y1;
		int r=(y0-1)*gcd/a,l=(1-x0)*gcd/b +( ((1-x0) * gcd % b)!=0);
		cout << r <<" "<<l<<"\n";
		int minx=min( x0+l*b/gcd,x0+r*b/gcd),maxx=max( x0+l*b/gcd,x0+r*b/gcd);
		int miny=min( y0-l*a/gcd,y0-r*a/gcd),maxy=max( y0-l*a/gcd,y0-r*a/gcd);
		if(l>r)cout<<x0+l*b/gcd<<" "<<y0-r*a/gcd<<"\n";
		else cout<<r-l+1<<" "<<minx<<" "<<miny<<" "<<maxx<<" "<<maxy<<"\n";
	}
}
